const feeds = $input.all().map(i => i.json);
const feed = feeds.find(f => /sun[\s-]?times/i.test(f.title || ''));
if (!feed) throw new Error('Sun-Times feed not found in Miniflux');
return [{ json: { feedId: feed.id } }];

const all = $input.first().json.entries || [];
const skip = /obituar|dies at|dead at|in memoriam|death notice|horoscope|dear abby|crossword|puzzle|comics|murder|homicide|shooting|shot |stabb|fatal|killed|slain|body found|carjack/i;
const priority = /\btrans\b|transgender|gender-affirming|nonbinary|non-binary|lgbt|drag show|drag brunch/i;
const isPriority = e => priority.test(`${e.title} ${e.url}`);
const entries = all.filter(e => isPriority(e) || !skip.test(`${e.title} ${e.url}`));
if (!entries.length) throw new Error('no Sun-Times entries in the last 7 days');
const WORDS = 40;
const text = entries.map(e => {
  const snippet = (e.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').slice(0, WORDS).join(' ');
  return `${isPriority(e) ? '[P] ' : '- '}${e.title} (${e.published_at.slice(0, 10)}): ${snippet}`;
}).join('\n');
const sat = $now.plus({ days: 1 }).toFormat('MMM d');
const sun = $now.plus({ days: 2 }).toFormat('MMM d');
const payload = {
  model: 'qwen3',
  temperature: 0.3,
  response_format: { type: 'json_schema', json_schema: { name: 'digest', schema: { type: 'object', properties: { week: { type: 'array', items: { type: 'string' } }, weekend: { type: 'array', items: { type: 'string' } } }, required: ['week', 'weekend'] } } },
  messages: [
    { role: 'system', content: 'You write ultra-concise dashboard digests as JSON. /no_think' },
    { role: 'user', content: `From this week's Chicago Sun-Times articles, build a "Chicago Happenings" digest as JSON. "week": at most 6 bullets, top local stories, especially city/state politics. "weekend": at most 6 bullets, events, openings, games, and closures happening Sat ${sat} or Sun ${sun}. Each bullet is ONE plain sentence, 18 words max, rewritten in your own words -- never copy article text, no dates, no markers. Articles tagged [P] are priority: always include them first in their section (drop the tag). Skip national wire stories.\n\n${text}` }
  ]
};
return [{ json: { payload, count: entries.length } }];

const d = JSON.parse($input.first().json.choices[0].message.content);
const s = $getWorkflowStaticData('global');
s.digest = { week: d.week, weekend: d.weekend, updated: $now.toISO() };
return [{ json: s.digest }];
